31	let state = {
32	  status: "idle",   // idle | running | done | failed
33	  runId: null,
34	  params: null,
35	  startedAt: null,
36	  finishedAt: null,
37	  exitCode: null,
38	  pid: null,
39	  logLines: [],
40	};
41	
42	let currentProcess = null;
43	
44	function appendLog(line) {
45	  state.logLines.push(line);
46	  if (state.logLines.length > MAX_LOG_LINES) state.logLines.shift();
47	  process.stdout.write(line + "\n");
48	}
