124	    res.end(`<!DOCTYPE html>
125	<html lang="en">
126	<head>
127	  <meta charset="utf-8">
128	  <title>Judge AI Dredd — Test 7</title>
129	  <style>
130	    body { font-family: monospace; background: #111; color: #ccc; padding: 2em; margin: 0; }
131	    h1   { color: #fff; margin-top: 0; }
132	    h2   { color: #aaa; }
133	    .badge { display: inline-block; padding: .2em .8em; border-radius: 3px;
134	             background: ${colour}; color: #fff; font-weight: bold; }
135	    code { background: #1a1a1a; padding: .1em .4em; border-radius: 2px; }
136	    pre  { background: #1a1a1a; padding: 1em; border-radius: 4px;
137	           overflow: auto; max-height: 60vh; white-space: pre-wrap; word-break: break-all; }
138	    table { border-collapse: collapse; margin-top: .5em; }
139	    td, th { padding: .2em 1em .2em 0; text-align: left; }
140	  </style>
141	</head>
142	<body>
143	  <h1>Judge AI Dredd — Test 7</h1>
144	  <p style="color:#666;margin-top:-.5em">v${BUILD_VERSION}</p>
145	  <table>
146	    <tr><th>Status</th>   <td><span class="badge">${state.status}</span></td></tr>
147	    ${state.runId      ? `<tr><th>Run ID</th>    <td><code>${state.runId}</code></td></tr>` : ""}
148	    ${state.startedAt  ? `<tr><th>Started</th>   <td><code>${state.startedAt}</code></td></tr>` : ""}
149	    ${state.finishedAt ? `<tr><th>Finished</th>  <td><code>${state.finishedAt}</code> (exit ${state.exitCode})</td></tr>` : ""}
150	    ${state.pid        ? `<tr><th>PID</th>       <td><code>${state.pid}</code></td></tr>` : ""}
151	  </table>
152	  ${state.status === "idle"
153	    ? "<p>No run in progress. <code>POST /run</code> with a JSON body to start one.</p>"
154	    : ""}
155	  <h2>Log (last ${state.logLines.length} lines)</h2>
156	  <pre>${logHtml || "(empty)"}</pre>
157	</body>
158	</html>`);
159	    return;
160	  }
161	
162	  // ── GET /status — JSON state ──────────────────────────────────────────────
163	  if (req.method === "GET" && url.pathname === "/status") {
164	    res.writeHead(200, { "Content-Type": "application/json" });
165	    res.end(JSON.stringify({
166	      version:     BUILD_VERSION,
167	      status:      state.status,
168	      runId:       state.runId,
169	      params:      state.params,
170	      startedAt:   state.startedAt,
171	      finishedAt:  state.finishedAt,
172	      exitCode:    state.exitCode,
173	      pid:         state.pid,
174	      bufferedLogLines: state.logLines.length,
175	    }));
176	    return;
177	  }
178	
179	  // ── GET /logs — plain-text log tail ──────────────────────────────────────
180	  if (req.method === "GET" && url.pathname === "/logs") {
181	    const n = Math.min(parseInt(url.searchParams.get("n") || "100", 10), MAX_LOG_LINES);
182	    res.writeHead(200, { "Content-Type": "text/plain; charset=utf-8" });
183	    res.end(state.logLines.slice(-n).join("\n"));
184	    return;
185	  }
186	
187	  // ── POST /run — start a run ───────────────────────────────────────────────
188	  if (req.method === "POST" && url.pathname === "/run") {
189	    if (state.status === "running") {
190	      res.writeHead(409, { "Content-Type": "application/json" });
191	      res.end(JSON.stringify({ error: "A run is already in progress", runId: state.runId }));
192	      return;
193	    }
194	
195	    let body = "";
196	    req.on("data", (chunk) => (body += chunk));
197	    req.on("end", () => {
198	      let params = {};
199	      try {
200	        if (body.trim()) params = JSON.parse(body);
201	      } catch {
202	        res.writeHead(400, { "Content-Type": "application/json" });
203	        res.end(JSON.stringify({ error: "Invalid JSON body" }));
204	        return;
205	      }
206	
207	      startRun(params);
208	      res.writeHead(202, { "Content-Type": "application/json" });
209	      res.end(JSON.stringify({ message: "Run started", runId: state.runId, status: "running" }));
210	    });
211	    return;
212	  }
213	
214	  res.writeHead(404, { "Content-Type": "application/json" });
215	  res.end(JSON.stringify({ error: "Not found", path: url.pathname }));
216	});
217	
218	server.listen(PORT, "0.0.0.0", () => {
219	  console.log(`Judge AI Dredd Test 7 v${BUILD_VERSION} listening on 0.0.0.0:${PORT}`);
220	  console.log("  GET  /        health check + status page");
221	  console.log("  GET  /status  JSON run state");
222	  console.log("  GET  /logs    plain-text log tail (?n=N)");
223	  console.log("  POST /run     start a run (JSON body with optional overrides)");
224	});
225	
226	// ---------------------------------------------------------------------------
227	// Graceful shutdown
228	// ---------------------------------------------------------------------------
229	
230	process.on("SIGTERM", () => {
231	  console.log("SIGTERM received — draining connections");
232	  server.close(() => {
233	    if (currentProcess) {
234	      console.log("Forwarding SIGTERM to runner process (pid " + currentProcess.pid + ")");
235	      currentProcess.kill("SIGTERM");
236	    }
237	    process.exit(0);
238	  });
239	});
