1	/**
2	 * Drift Detector
3	 *
4	 * Embedding-based semantic drift detection using a local model via Ollama.
5	 * Computes similarity between the original task and each turn's actions,
6	 * tracking cumulative drift and sudden shifts.
7	 *
8	 * This is Layer 1 of the defence: fast (~50ms per turn), deterministic
9	 * given the same embeddings, and runs entirely locally.
10	 */
11	
12	import { embedAny, cosineSimilarity } from "./ollama-client.js";
13	
14	export interface DriftScore {
15	  /** Cosine similarity between this turn's action and the original task (0-1) */
16	  similarity: number;
17	  /** Mean similarity across all turns so far (0-1, higher = more aligned) */
18	  meanSimilarity: number;
19	  /** Cumulative drift: 1 - meanSimilarity (0-1, higher = more drifted) */
20	  cumulativeDrift: number;
21	  /** Absolute change in similarity from previous turn */
22	  turnDelta: number;
23	  /** Number of turns tracked */
24	  turnCount: number;
25	  /** Embedding computation time in ms */
26	  embedTimeMs: number;
27	}
28	
29	export class DriftDetector {
30	  private embeddingModel: string;
31	  private taskEmbedding: number[] | null = null;
32	  private turnSimilarities: number[] = [];
33	  private previousSimilarity: number = 1.0;
34	
35	  constructor(embeddingModel = "nomic-embed-text") {
36	    this.embeddingModel = embeddingModel;
37	  }
38	
39	  /**
40	   * Register the original task. Computes and caches its embedding.
41	   */
42	  async registerGoal(task: string): Promise<void> {
43	    const embeddings = await embedAny(task, this.embeddingModel);
44	    this.taskEmbedding = embeddings[0];
45	    this.turnSimilarities = [];
46	    this.previousSimilarity = 1.0;
47	  }
48	
49	  /**
50	   * Summarise a turn's activity into a text string for embedding.
51	   * Focuses on WHAT was done, not conversational content.
52	   */
53	  summariseTurn(
54	    userMessage: string,
55	    toolCalls: { tool: string; input: Record<string, unknown> }[],
56	    assistantResponse: string
57	  ): string {
58	    const toolSummary =
59	      toolCalls.length > 0
60	        ? toolCalls
61	            .map((tc) => {
62	              const params = Object.entries(tc.input)
63	                .map(([k, v]) => `${k}=${JSON.stringify(v).substring(0, 80)}`)
64	                .join(", ");
65	              return `${tc.tool}(${params})`;
66	            })
67	            .join("; ")
68	        : "no tools used";
69	
70	    return (
71	      `User request: ${userMessage.substring(0, 200)}. ` +
72	      `Agent actions: ${toolSummary}. ` +
73	      `Agent response summary: ${assistantResponse.substring(0, 200)}`
74	    );
75	  }
76	
77	  /**
78	   * Evaluate semantic drift for a turn.
79	   */
80	  async evaluate(turnSummary: string): Promise<DriftScore> {
81	    if (!this.taskEmbedding) {
82	      throw new Error("Goal not registered. Call registerGoal() first.");
83	    }
84	
85	    const start = Date.now();
86	    const embeddings = await embedAny(turnSummary, this.embeddingModel);
87	    const embedTimeMs = Date.now() - start;
88	
89	    const turnEmbedding = embeddings[0];
90	    const similarity = cosineSimilarity(this.taskEmbedding, turnEmbedding);
91	
92	    this.turnSimilarities.push(similarity);
93	
94	    const meanSimilarity =
95	      this.turnSimilarities.reduce((a, b) => a + b, 0) /
96	      this.turnSimilarities.length;
97	
98	    const turnDelta = Math.abs(similarity - this.previousSimilarity);
99	    this.previousSimilarity = similarity;
100	
101	    return {
102	      similarity,
103	      meanSimilarity,
104	      cumulativeDrift: 1 - meanSimilarity,
105	      turnDelta,
106	      turnCount: this.turnSimilarities.length,
107	      embedTimeMs,
108	    };
109	  }
110	
111	  /**
112	   * Get the full similarity history.
113	   */
114	  getHistory(): number[] {
115	    return [...this.turnSimilarities];
116	  }
117	
118	  /**
119	   * Reset state for a new test run.
120	   */
121	  reset(): void {
122	    this.taskEmbedding = null;
123	    this.turnSimilarities = [];
124	    this.previousSimilarity = 1.0;
125	  }
126	}
