335	// =========================================================================
336	// POST /intent — UserPromptSubmit
337	// =========================================================================
338	async function handleIntent(req: IncomingMessage, res: ServerResponse) {
339	  const body = JSON.parse(await readBody(req));
340	  const { session_id, prompt, transcript_path, cwd } = body;
341	
342	  if (!session_id || !prompt) {
343	    return json(res, 400, { error: "Missing session_id or prompt" });
344	  }
345	
346	  // Store the Claude instance's working directory as the sandbox boundary.
347	  // setProjectRoot ignores subsequent calls so the first cwd wins.
348	  if (cwd) {
349	    tracker.setProjectRoot(session_id, cwd);
350	  }
351	
352	  // If this is a session we haven't seen and there's a transcript, backfill
353	  if (!registeredSessions.has(session_id) && transcript_path) {
354	    await backfillFromTranscript(session_id, transcript_path);
355	  }
356	
357	  // Allow per-request mode override (e.g., SDK sends mode in body)
358	  const mode: TrustMode = body.mode ?? CONFIG.mode;
359	
360	  const result = await tracker.registerIntent(session_id, prompt, mode === "interactive");
361	
362	  // Build a contextual goal: the user prompt combined with the assistant
363	  // response that immediately preceded it, so short replies retain meaning.
364	  const { priorAssistant } = transcript_path
365	    ? extractLastUserAndPriorAssistant(transcript_path)
366	    : { priorAssistant: null };
367	  const contextualGoal = buildContextualIntent(prompt, priorAssistant);
368	
369	  // Register goal with interceptor on first call per session
370	  if (result.isOriginal && !registeredSessions.has(session_id)) {
371	    await interceptor.registerGoal(contextualGoal);
372	    registeredSessions.add(session_id);
373	  }
374	
375	  if ((mode === "interactive" || mode === "learn") && !result.isOriginal) {
376	    // INTERACTIVE / LEARN MODE:
377	    // Every user prompt is trusted — they're steering.
378	    // But short confirmations ("yes", "ok", "do it", "go ahead") are
379	    // confirming the PREVIOUS intent, not setting a new one.
380	    // Only update the goal for substantive prompts.
381	    // Learn mode also updates intent so pipeline verdicts are evaluated
382	    // against the actual current goal, not a stale first prompt.
383	    const isConfirmation =
384	      /^\s*(yes|yeah|yep|ok|okay|sure|do it|go ahead|go|proceed|continue|y|k|confirm|approved?|lgtm|ship it|sounds good|that's right|correct|exactly|please|thanks|thank you|👍)\b/i.test(prompt)
385	      && prompt.trim().length < 80;
386	
387	    if (isConfirmation) {
388	      console.log(
389	        `  [${session_id.substring(0, 8)}] [INTENT] ${mode} mode: "${prompt.trim()}" is a confirmation — keeping previous goal`
390	      );
391	    } else {
392	      await interceptor.registerGoal(contextualGoal);
393	      console.log(
394	        `  [${session_id.substring(0, 8)}] [INTENT] ${mode} mode: updated goal to "${prompt.substring(0, 60)}..." ` +
395	        `(prior assistant context: ${priorAssistant ? "yes" : "no"}, ` +
396	        `drift from original: ${result.driftFromOriginal?.toFixed(3) ?? "n/a"})`
397	      );
398	    }
399	  }
400	
401	  // Get appropriate reminder (only in autonomous mode)
402	  const classification = tracker.classifyDrift(result.driftFromOriginal);
403	  const reminder = mode === "autonomous"
404	    ? tracker.getGoalReminder(session_id, result.driftFromOriginal)
405	    : null;
406	
407	  // Build hook response
408	  const hookResponse: Record<string, unknown> = {};
409	
410	  if (reminder) {
411	    hookResponse.systemMessage = reminder;
412	  }
413	
414	  addFeed({
415	    timestamp: new Date().toISOString(),
416	    type: "intent",
417	    prompt: prompt.substring(0, 100),
418	    sessionId: session_id,
419	    reason: `Turn ${result.turnNumber}: ${classification}${result.driftFromOriginal !== null ? ` (drift: ${result.driftFromOriginal.toFixed(3)})` : ""}`,
420	  });
421	
422	  json(res, 200, {
423	    ...hookResponse,
424	    _meta: {
425	      isOriginal: result.isOriginal,
426	      turnNumber: result.turnNumber,
427	      driftFromOriginal: result.driftFromOriginal,
428	      driftFromPrevious: result.driftFromPrevious,
429	      classification,
430	    },
431	  });
432	}
