434	// =========================================================================
435	// POST /evaluate — PreToolUse
436	// =========================================================================
437	async function handleEvaluate(req: IncomingMessage, res: ServerResponse) {
438	  const body = JSON.parse(await readBody(req));
439	  const { session_id, tool_name, tool_input, agent_reasoning, transcript_path } = body;
440	  const mode: TrustMode = body.mode ?? CONFIG.mode;
441	  const isLearn = mode === "learn";
442	
443	  if (!session_id || !tool_name) {
444	    return json(res, 400, { error: "Missing session_id or tool_name" });
445	  }
446	
447	  // If no goal registered yet, try backfill or fail-open
448	  if (!registeredSessions.has(session_id)) {
449	    if (transcript_path) {
450	      await backfillFromTranscript(session_id, transcript_path);
451	    }
452	
453	    // Still no goal after backfill? Allow the call — we can't evaluate
454	    // drift without a baseline. Policy deny list still applies (except in
455	    // learn mode, which only observes).
456	    if (!registeredSessions.has(session_id)) {
457	      const projectRoot = tracker.getProjectRoot(session_id);
458	      const policyOnly = (await import("./tool-policy.js")).evaluateToolPolicy(tool_name, tool_input ?? {}, projectRoot);
459	      if (policyOnly.decision === "deny" && !isLearn) {
460	        return json(res, 200, {
461	          hookSpecificOutput: {
462	            hookEventName: "PreToolUse",
463	            permissionDecision: "deny",
464	            permissionDecisionReason: `Judge Dredd (no goal): ${policyOnly.reason}`,
465	          },
466	          _meta: { allowed: false, stage: "policy-deny", reason: policyOnly.reason },
467	        });
468	      }
469	      // Allow — no goal to drift from, policy didn't deny
470	      return json(res, 200, {
471	        hookSpecificOutput: {
472	          hookEventName: "PreToolUse",
473	          permissionDecision: "allow",
474	          permissionDecisionReason: "Judge Dredd: no goal registered yet, policy allows",
475	        },
476	        _meta: { allowed: true, stage: "no-goal-allow", reason: "No goal registered, policy allows" },
477	      });
478	    }
479	  }
480	
481	  // Build file context for Bash/git commands
482	  let fileContext: string | undefined;
483	  if (tool_name === "Bash") {
484	    const command = String(tool_input?.command ?? "");
485	    const writtenFiles = tracker.getWrittenFiles(session_id);
486	
487	    const referencesWritten = writtenFiles.some((f) =>
488	      command.includes(f.path) || command.includes(f.path.split("/").pop()!)
489	    );
490	
491	    if (referencesWritten || /git\s+(add|commit|push)/.test(command)) {
492	      fileContext = tracker.getFileContextForJudge(session_id);
493	    }
494	  }
495	
496	  // Combine file context and agent reasoning for the judge
497	  let fullContext = fileContext ?? "";
498	  if (agent_reasoning) {
499	    fullContext = (fullContext ? fullContext + "\n\n" : "") +
500	      `AGENT REASONING (why it wants to use this tool):\n${agent_reasoning}`;
501	  }
502	
503	  const result = await interceptor.evaluate(
504	    tool_name,
505	    tool_input ?? {},
506	    fullContext || undefined,
507	    session_id,
508	    tracker.getProjectRoot(session_id)
509	  );
510	
511	  // In learn mode, the pipeline still runs (for logging/observation) but
512	  // we never block — the would-be verdict is recorded as-is.
513	  const effectiveAllowed = isLearn ? true : result.allowed;
514	
515	  // Record the decision (true verdict, not the learn-mode override)
516	  tracker.recordToolCall(
517	    session_id,
518	    tool_name,
519	    tool_input ?? {},
520	    result.allowed ? "allow" : "deny",
521	    result.similarity
522	  );
523	
524	  addFeed({
525	    timestamp: new Date().toISOString(),
526	    type: "tool",
527	    tool: tool_name,
528	    stage: isLearn && !result.allowed ? `${result.stage} (learn-allow)` : result.stage,
529	    allowed: effectiveAllowed,
530	    reason: result.reason.substring(0, 100),
531	    sessionId: session_id,
532	  });
533	
534	  if (isLearn && !result.allowed) {
535	    console.log(
536	      `  [${session_id.substring(0, 8)}] [LEARN] Would have blocked ${tool_name}: ${result.reason} — allowing anyway`
537	    );
538	  }
539	
540	  // Build hook response
541	  const hookResponse: Record<string, unknown> = {};
542	
543	  if (!effectiveAllowed) {
544	    // Use the interceptor's *current* working goal (which interactive mode
545	    // updates each turn) rather than the session's stale very-first prompt.
546	    const currentGoal = interceptor.getCurrentGoal()
547	      || tracker.getSessionContext(session_id).originalTask
548	      || "unknown";
549	    // Strip the contextual "PREVIOUS ASSISTANT RESPONSE: ..." prefix when
550	    // surfacing to the user — they only need to see the actual user prompt.
551	    const userVisibleGoal = currentGoal.includes("USER PROMPT:\n")
552	      ? currentGoal.split("USER PROMPT:\n").pop()!.trim()
553	      : currentGoal;
554	    hookResponse.hookSpecificOutput = {
555	      hookEventName: "PreToolUse",
556	      permissionDecision: "deny",
557	      permissionDecisionReason: `Judge Dredd: ${result.reason}`,
558	    };
559	    hookResponse.systemMessage =
560	      `[SECURITY] Tool call ${tool_name} was blocked. Reason: ${result.reason}. ` +
561	      `Stay focused on the current task: "${userVisibleGoal}".`;
562	  } else {
563	    // Explicitly allow — required for dontAsk/trusted mode
564	    hookResponse.hookSpecificOutput = {
565	      hookEventName: "PreToolUse",
566	      permissionDecision: "allow",
567	      permissionDecisionReason: `Judge Dredd: ${result.reason}`,
568	    };
569	  }
570	
571	  json(res, 200, {
572	    ...hookResponse,
573	    _meta: {
574	      allowed: result.allowed,
575	      stage: result.stage,
576	      similarity: result.similarity,
577	      reason: result.reason,
578	      evaluationMs: result.evaluationMs,
579	      judgeVerdict: result.judgeVerdict
580	        ? {
581	            verdict: result.judgeVerdict.verdict,
582	            confidence: result.judgeVerdict.confidence,
583	            reasoning: result.judgeVerdict.reasoning,
584	          }
585	        : null,
586	    },
587	  });
588	}
