641	async function handleEnd(req: IncomingMessage, res: ServerResponse) {
642	  const body = JSON.parse(await readBody(req));
643	  const { session_id } = body;
644	
645	  if (!session_id) {
646	    return json(res, 400, { error: "Missing session_id" });
647	  }
648	
649	  const summary = tracker.getFullSessionSummary(session_id);
650	  const ctx = tracker.getSessionContext(session_id);
651	  const driftHistory = tracker.getDriftDetector(session_id).getHistory();
652	
653	  // Write log
654	  const logDir = CONFIG.logDir;
655	  try { mkdirSync(logDir, { recursive: true }); } catch {}
656	
657	  const logFile = join(
658	    logDir,
659	    `session-${session_id.substring(0, 12)}-${new Date().toISOString().replace(/[:.]/g, "-")}.json`
660	  );
661	
662	  const sessionLog = {
663	    sessionId: session_id,
664	    timestamp: new Date().toISOString(),
665	    originalTask: ctx.originalTask,
666	    summary,
667	    toolHistory: ctx.recentTools,
668	    filesWritten: tracker.getWrittenFiles(session_id).map((f) => ({
669	      path: f.path,
670	      writeCount: f.writeCount,
671	      containsCanary: f.containsCanary,
672	    })),
673	    envVars: tracker.getEnvVars(session_id),
674	    driftHistory,
675	    turnMetrics: summary.turnMetrics,
676	    interceptorLog: interceptor.getLog().map((r) => ({
677	      tool: r.tool,
678	      input: r.input,
679	      stage: r.stage,
680	      allowed: r.allowed,
681	      similarity: r.similarity,
682	      reason: r.reason,
683	      evaluationMs: r.evaluationMs,
684	    })),
685	  };
686	
687	  writeFileSync(logFile, JSON.stringify(sessionLog, null, 2));
688	
689	  console.log(
690	    `[END] Session ${session_id.substring(0, 8)}: ` +
691	    `${summary.turns} turns, ${summary.toolCalls} tools, ` +
692	    `${summary.denied} denied → ${logFile}`
693	  );
694	
695	  // Cleanup
696	  registeredSessions.delete(session_id);
697	  tracker.endSession(session_id);
698	
699	  json(res, 200, { logFile, summary });
700	}
