732	// =========================================================================
733	async function handleCompact(req: IncomingMessage, res: ServerResponse) {
734	  const body = JSON.parse(await readBody(req));
735	  const { session_id } = body;
736	
737	  if (!session_id) {
738	    return json(res, 400, { error: "Missing session_id" });
739	  }
740	
741	  // Context is being compacted — the model will lose older conversation.
742	  // We keep our full tracking state but note the boundary.
743	  console.log(
744	    `  [COMPACT] Session ${session_id.substring(0, 8)}: context compaction detected`
745	  );
746	
747	  // Don't pivot — the intent hasn't changed, just the model's memory.
748	  // But record it in metrics so we know when it happened.
749	  const session = tracker.getSessionContext(session_id);
750	  tracker.recordTurnMetrics(
751	    session_id,
752	    null, // no drift measurement at compaction
753	    null,
754	    0,
755	    0,
756	    false,
757	    false
758	  );
759	
760	  json(res, 200, { noted: true });
761	}
