1	/**
2	 * Session Tracker
3	 *
4	 * Maintains per-session state across hook invocations, tracking:
5	 *   - Original intent (from first UserPromptSubmit)
6	 *   - Turn-by-turn intent history (from subsequent UserPromptSubmit calls)
7	 *   - Tool call history (from PreToolUse calls)
8	 *   - Embedding trajectories for drift detection
9	 *
10	 * This is the stateful backbone that connects the hooks:
11	 *   UserPromptSubmit → registers intent
12	 *   PreToolUse → evaluates tool call against intent history
13	 *
14	 * Keyed by session_id so multiple concurrent sessions stay isolated.
15	 */
16	
17	import { DriftDetector } from "./drift-detector.js";
