94	export interface SessionState {
95	  sessionId: string;
96	  /** The first prompt — the original task */
97	  originalIntent: TurnIntent | null;
98	  /** All subsequent prompts — turn-by-turn intent history */
99	  turnIntents: TurnIntent[];
100	  /** All tool calls evaluated */
101	  toolHistory: ToolCallRecord[];
102	  /** Current turn number */
103	  currentTurn: number;
104	  /** Drift detector instance for this session */
105	  driftDetector: DriftDetector;
106	  /** Embedding of the original task */
107	  originalEmbedding: number[] | null;
108	  /** Files written/edited during this session (keyed by path) */
109	  filesWritten: Map<string, FileRecord>;
110	  /** Files read during this session */
111	  filesRead: FileReadRecord[];
112	  /** Environment variables set/modified during this session */
113	  envVars: Map<string, EnvVarRecord>;
114	  /** Per-turn metrics for logging and analysis */
115	  turnMetrics: TurnMetrics[];
116	  /** Working directory of the Claude instance — defines the sandbox boundary */
