120	export class SessionTracker {
121	  private sessions = new Map<string, SessionState>();
122	  private embeddingModel: string;
123	
124	  constructor(embeddingModel = "nomic-embed-text") {
125	    this.embeddingModel = embeddingModel;
126	  }
