128	  /**
129	   * Get or create session state.
130	   */
131	  private getSession(sessionId: string): SessionState {
132	    if (!this.sessions.has(sessionId)) {
133	      this.sessions.set(sessionId, {
134	        sessionId,
135	        originalIntent: null,
136	        turnIntents: [],
137	        toolHistory: [],
138	        currentTurn: 0,
139	        driftDetector: new DriftDetector(this.embeddingModel),
140	        originalEmbedding: null,
141	        filesWritten: new Map(),
142	        filesRead: [],
143	        envVars: new Map(),
144	        turnMetrics: [],
145	        projectRoot: null,
146	      });
147	    }
148	    return this.sessions.get(sessionId)!;
149	  }
