151	  /**
152	   * Record the working directory of the Claude instance for sandbox enforcement.
153	   * Called once on session registration (UserPromptSubmit). Ignored if already set
154	   * so that subsequent prompts don't overwrite the original boundary.
155	   */
156	  setProjectRoot(sessionId: string, cwd: string): void {
157	    const session = this.getSession(sessionId);
158	    if (!session.projectRoot) {
159	      session.projectRoot = cwd;
160	    }
161	  }
162	
163	  getProjectRoot(sessionId: string): string | null {
164	    return this.sessions.get(sessionId)?.projectRoot ?? null;
165	  }
