167	  /**
168	   * Called from UserPromptSubmit hook.
169	   * First call = original intent. Subsequent calls = turn intents.
170	   */
171	  /**
172	   * Reset a session's tracking state for a new direction while preserving
173	   * the session ID and history log. Called when the user explicitly changes
174	   * direction in interactive mode, or when context is compacted.
175	   *
176	   * The previous intent chain is archived, and the next prompt becomes
177	   * the new "original intent" for drift comparison.
178	   */
179	  async pivotSession(sessionId: string, reason: string): Promise<void> {
180	    const session = this.getSession(sessionId);
181	
182	    const prevOriginal = session.originalIntent?.prompt ?? "(none)";
183	    const prevTurns = session.currentTurn;
184	
185	    console.log(
186	      `  [PIVOT] Session ${sessionId.substring(0, 8)}: resetting after ${prevTurns} turns`
187	    );
188	    console.log(`  [PIVOT] Previous intent: "${prevOriginal.substring(0, 60)}..."`);
189	    console.log(`  [PIVOT] Reason: ${reason}`);
190	
191	    // Archive the old state into turn metrics as a boundary marker
192	    session.turnMetrics.push({
193	      turnNumber: session.currentTurn,
194	      timestamp: new Date().toISOString(),
195	      driftFromOriginal: null,
196	      driftFromPrevious: null,
197	      classification: "on-task",
198	      toolCallCount: 0,
199	      toolCallsDenied: 0,
200	      goalReminderInjected: false,
201	      blocked: false,
202	    });
203	
204	    // Reset tracking state but keep the session
205	    session.originalIntent = null;
206	    session.originalEmbedding = null;
207	    session.turnIntents = [];
208	    session.currentTurn = 0;
209	    session.driftDetector = new DriftDetector(this.embeddingModel);
210	    session.filesWritten = new Map();
211	    session.filesRead = [];
212	    session.envVars = new Map();
213	    // toolHistory and turnMetrics are preserved for the full session log
214	  }
215	
216	  async registerIntent(sessionId: string, prompt: string, skipDrift = false): Promise<{
217	    isOriginal: boolean;
218	    turnNumber: number;
219	    driftFromOriginal: number | null;
220	    driftFromPrevious: number | null;
221	  }> {
222	    const session = this.getSession(sessionId);
223	    // In interactive mode (skipDrift) we don't need an embedding for the
224	    // turn prompt — drift from original isn't meaningful when the user is
225	    // actively steering and the goal updates each turn.
226	    const promptEmbedding = skipDrift && session.originalIntent !== null
227	      ? null
228	      : (await embedAny(prompt, this.embeddingModel))[0];
229	
230	    const intent: TurnIntent = {
231	      turnNumber: session.currentTurn,
232	      timestamp: new Date().toISOString(),
233	      prompt,
234	      embedding: promptEmbedding ?? [],
235	    };
236	
237	    let driftFromOriginal: number | null = null;
238	    let driftFromPrevious: number | null = null;
239	
240	    if (session.originalIntent === null) {
241	      // First prompt — this is the original task
242	      session.originalIntent = intent;
243	      session.originalEmbedding = promptEmbedding;
244	      await session.driftDetector.registerGoal(prompt);
245	
246	      console.log(
247	        `  [SESSION ${sessionId.substring(0, 8)}] ORIGINAL INTENT registered: "${prompt.substring(0, 80)}..."`
248	      );
249	    } else {
250	      // Subsequent prompt — track as turn intent
251	      session.turnIntents.push(intent);
252	      session.currentTurn++;
253	
254	      if (!skipDrift && promptEmbedding) {
255	        // Measure drift from original
256	        driftFromOriginal = 1 - cosineSimilarity(
257	          session.originalEmbedding!,
258	          promptEmbedding
259	        );
260	
261	        // Measure drift from previous turn
262	        const prevIntents = session.turnIntents;
263	        if (prevIntents.length >= 2) {
264	          const prevEmbedding = prevIntents[prevIntents.length - 2].embedding;
265	          if (prevEmbedding.length > 0) {
266	            driftFromPrevious = 1 - cosineSimilarity(prevEmbedding, promptEmbedding);
267	          }
268	        }
269	
270	        console.log(
271	          `  [SESSION ${sessionId.substring(0, 8)}] TURN ${session.currentTurn} intent: "${prompt.substring(0, 80)}..." ` +
272	          `(drift from original: ${driftFromOriginal?.toFixed(3) ?? "n/a"}, ` +
273	          `from prev: ${driftFromPrevious?.toFixed(3) ?? "n/a"})`
274	        );
275	      } else {
276	        console.log(
277	          `  [SESSION ${sessionId.substring(0, 8)}] TURN ${session.currentTurn} intent: "${prompt.substring(0, 80)}..." (interactive)`
278	        );
279	      }
280	    }
281	
282	    return {
283	      isOriginal: session.originalIntent === intent,
284	      turnNumber: session.currentTurn,
285	      driftFromOriginal,
286	      driftFromPrevious,
287	    };
288	  }
