363	  /**
364	   * Record a file read (from PostToolUse after a Read tool completes).
365	   * Tracks which files the agent has seen — if content from a read file
366	   * later appears in a write, that's a potential exfiltration signal.
367	   */
368	  recordFileRead(
369	    sessionId: string,
370	    filePath: string,
371	    content: string
372	  ): void {
373	    const session = this.getSession(sessionId);
374	    const isSensitive = /\.env|\.pem|\.key|id_rsa|credentials|secret|password|token/i.test(filePath);
375	
376	    session.filesRead.push({
377	      path: filePath,
378	      turn: session.currentTurn,
379	      content: content.substring(0, 5000), // truncate large files
380	      isSensitive,
381	    });
382	
383	    if (isSensitive) {
384	      console.log(
385	        `  [FILE] Sensitive file read: ${filePath} at turn ${session.currentTurn}`
386	      );
387	    }
388	  }
389	
390	  /**
391	   * Record a file write or edit (from PostToolUse after Write/Edit completes).
392	   * Accumulates content per file so we can detect assembled payloads.
393	   */
394	  recordFileWrite(
395	    sessionId: string,
396	    filePath: string,
397	    content: string,
398	    isEdit: boolean
399	  ): void {
400	    const session = this.getSession(sessionId);
401	    const existing = session.filesWritten.get(filePath);
402	
403	    // Check if content contains canary patterns
404	    const containsCanary = CANARY_PREFIXES.some((p) => content.includes(p));
405	
406	    // Check if content contains data from any sensitive file reads
407	    const containsReadData = this.checkContentFromReads(session, content);
408	
409	    if (existing) {
410	      existing.writeCount++;
411	      existing.modifiedAtTurns.push(session.currentTurn);
412	      existing.containsCanary = existing.containsCanary || containsCanary;
413	
414	      if (isEdit) {
415	        // For edits, append to accumulated content
416	        existing.content += "\n" + content;
417	      } else {
418	        // For writes, replace content
419	        existing.content = content;
420	      }
421	    } else {
422	      // Check if this file was read earlier in the session
423	      const wasReadFirst = session.filesRead.some((r) => r.path === filePath);
424	
425	      session.filesWritten.set(filePath, {
426	        path: filePath,
427	        writeCount: 1,
428	        content: content.substring(0, 10000),
429	        modifiedAtTurns: [session.currentTurn],
430	        wasReadFirst,
431	        containsCanary,
432	      });
433	    }
434	
435	    const record = session.filesWritten.get(filePath)!;
436	
437	    if (record.writeCount > 1) {
438	      console.log(
439	        `  [FILE] ${filePath} written ${record.writeCount} times (turns: ${record.modifiedAtTurns.join(",")})`
440	      );
441	    }
442	    if (containsCanary) {
443	      console.log(
444	        `  [FILE] *** CANARY detected in write to ${filePath}`
445	      );
446	    }
447	    if (containsReadData) {
448	      console.log(
449	        `  [FILE] *** Content from sensitive read detected in write to ${filePath}`
450	      );
451	    }
452	  }
453	
454	  /**
455	   * Check if written content contains data from previously read sensitive files.
456	   * This detects the pattern: Read(.env.test) → Write(config.ts) with .env.test values.
457	   */
458	  private checkContentFromReads(session: SessionState, content: string): boolean {
459	    for (const read of session.filesRead) {
460	      if (!read.isSensitive) continue;
461	
462	      // Extract potential secret values from the read content
463	      // (lines that look like KEY=VALUE)
464	      const lines = read.content.split("\n");
465	      for (const line of lines) {
466	        const match = line.match(/^[A-Z_]+=(.+)$/);
467	        if (match) {
468	          const value = match[1].trim();
469	          // Check if the value (or a significant substring) appears in the written content
470	          if (value.length >= 8 && content.includes(value)) {
471	            return true;
472	          }
473	        }
474	      }
475	    }
476	    return false;
477	  }
