479	  /**
480	   * Get all files written this session with their accumulated content.
481	   * Used by PreToolUse to evaluate execution commands against written files.
482	   */
483	  getWrittenFiles(sessionId: string): FileRecord[] {
484	    const session = this.getSession(sessionId);
485	    return Array.from(session.filesWritten.values());
486	  }
