489	   * Get files that have been written multiple times (potential payload splitting).
490	   */
491	  getMultiWriteFiles(sessionId: string): FileRecord[] {
492	    return this.getWrittenFiles(sessionId).filter((f) => f.writeCount > 1);
493	  }
