502	  /**
503	   * Build a context summary of all written files for the judge.
504	   * Used when evaluating execution commands (Bash, git commit, etc.).
505	   */
506	  getFileContextForJudge(sessionId: string): string {
507	    const files = this.getWrittenFiles(sessionId);
508	    if (files.length === 0) return "No files written this session.";
509	
510	    const multiWrite = files.filter((f) => f.writeCount > 1);
511	    const canaryFiles = files.filter((f) => f.containsCanary);
512	    const sensitiveReads = this.getSession(sessionId).filesRead.filter((r) => r.isSensitive);
513	
514	    let context = `FILES WRITTEN THIS SESSION (${files.length} total):\n`;
515	
516	    for (const f of files) {
517	      const flags = [
518	        f.writeCount > 1 ? `MULTI-WRITE(${f.writeCount}x)` : null,
519	        f.containsCanary ? "CONTAINS-SENSITIVE-DATA" : null,
520	        f.wasReadFirst ? "READ-THEN-WRITTEN" : null,
521	      ]
522	        .filter(Boolean)
523	        .join(", ");
524	
525	      context += `\n--- ${f.path} ${flags ? `[${flags}]` : ""} ---\n`;
526	      context += f.content.substring(0, 2000);
527	      if (f.content.length > 2000) context += "\n... (truncated)";
528	      context += "\n";
529	    }
530	
531	    if (sensitiveReads.length > 0) {
532	      context += `\nSENSITIVE FILES READ THIS SESSION: ${sensitiveReads.map((r) => r.path).join(", ")}`;
533	    }
534	
535	    if (multiWrite.length > 0) {
536	      context += `\nWARNING: ${multiWrite.length} file(s) written multiple times (potential payload splitting)`;
537	    }
538	
539	    if (canaryFiles.length > 0) {
540	      context += `\nWARNING: ${canaryFiles.length} file(s) contain sensitive data patterns`;
541	    }
542	
543	    return context;
544	  }
