550	  /**
551	   * Record an environment variable mutation detected in a Bash command.
552	   * Call from PostToolUse after a Bash command completes.
553	   */
554	  recordEnvVar(
555	    sessionId: string,
556	    command: string
557	  ): void {
558	    const session = this.getSession(sessionId);
559	
560	    // Detect export VAR=value
561	    const exportMatches = command.matchAll(/\bexport\s+([A-Z_][A-Z0-9_]*)=["']?([^"'\s;]+)["']?/g);
562	    for (const match of exportMatches) {
563	      this.addEnvVar(session, match[1], match[2], "export");
564	    }
565	
566	    // Detect VAR=value (inline assignment)
567	    const assignMatches = command.matchAll(/^([A-Z_][A-Z0-9_]*)=["']?([^"'\s;]+)["']?/gm);
568	    for (const match of assignMatches) {
569	      this.addEnvVar(session, match[1], match[2], "assignment");
570	    }
571	
572	    // Detect writes to shell config files
573	    if (/>>?\s*(~\/\.bashrc|~\/\.zshrc|~\/\.profile|~\/\.bash_profile|\.env)/.test(command)) {
574	      // Extract any VAR=value patterns in the echoed content
575	      const echoMatches = command.matchAll(/echo\s+["']?([A-Z_][A-Z0-9_]*)=([^"'\s]+)["']?\s*>>/g);
576	      for (const match of echoMatches) {
577	        this.addEnvVar(session, match[1], match[2], "shell-config");
578	      }
579	    }
580	  }
