593	      turn: session.currentTurn,
594	      source,
595	      isSensitive,
596	    });
597	
598	    console.log(
599	      `  [ENV] ${name}=${isSensitive ? "****" : value.substring(0, 30)} (${source}, turn ${session.currentTurn})${isSensitive ? " [SENSITIVE]" : ""}`
600	    );
