1	/**
2	 * PreToolUse Interceptor
3	 *
4	 * Evaluates every tool call BEFORE execution using a three-stage pipeline:
5	 *
6	 *   Stage 1: Policy engine (instant)
7	 *     → ALLOW: skip to execution
8	 *     → DENY:  block immediately
9	 *     → REVIEW: proceed to Stage 2
10	 *
11	 *   Stage 2: Embedding drift check (~50ms)
12	 *     Compares "tool + parameters" against original task embedding.
13	 *     If similarity is high → allow
14	 *     If drift detected → proceed to Stage 3
15	 *
16	 *   Stage 3: LLM judge (~5-15s)
17	 *     Asks local LLM: "Given original task X, is tool call Y appropriate?"
18	 *     Returns allow/deny.
19	 *
20	 * This runs at PreToolUse, so blocked tools never execute.
21	 * The agent receives a rejection message and must try a different approach.
22	 */
23	
24	import {
25	  evaluateToolPolicy,
26	  formatPolicyResult,
27	  type PolicyResult,
28	} from "./tool-policy.js";
29	import { DriftDetector } from "./drift-detector.js";
30	import { IntentJudge, type JudgeVerdict, type JudgeBackend } from "./intent-judge.js";
31	import { checkOllama, embedAny, isBedrockModel, chat } from "./ollama-client.js";
32	import { checkBedrock, bedrockChat, bedrockEmbed } from "./bedrock-client.js";
33	
34	export interface InterceptorConfig {
35	  embeddingModel?: string;
36	  judgeModel?: string;
37	  /** Which backend to use for the judge LLM (default: ollama) */
38	  judgeBackend?: JudgeBackend;
39	  /** Similarity threshold below which the judge is invoked (default: 0.5) */
40	  reviewThreshold?: number;
41	  /** Similarity threshold below which the tool is auto-denied (default: 0.3) */
42	  denyThreshold?: number;
43	  /** Enable LLM judge for REVIEW decisions (default: true) */
44	  enableJudge?: boolean;
45	}
46	
47	const DEFAULTS: Required<InterceptorConfig> = {
48	  embeddingModel: "eu.cohere.embed-v4:0",
49	  judgeModel: "nemotron-3-super",
50	  judgeBackend: "ollama",
51	  reviewThreshold: 0.6,
52	  denyThreshold: 0.15,
53	  enableJudge: true,
54	};
55	
56	export interface InterceptionResult {
57	  allowed: boolean;
58	  tool: string;
59	  input: Record<string, unknown>;
60	  /** Which stage made the decision */
61	  stage: "policy-allow" | "policy-deny" | "drift-allow" | "drift-deny" | "judge-allow" | "judge-deny";
62	  policyResult: PolicyResult;
63	  /** Embedding similarity (null if not evaluated) */
64	  similarity: number | null;
65	  /** Judge verdict (null if not invoked) */
66	  judgeVerdict: JudgeVerdict | null;
67	  /** Total evaluation time in ms */
68	  evaluationMs: number;
69	  /** Reason for the decision */
70	  reason: string;
71	}
72	
73	export class PreToolInterceptor {
74	  private config: Required<InterceptorConfig>;
75	  private driftDetector: DriftDetector;
76	  private judge: IntentJudge;
77	  private originalTask: string = "";
78	  private toolLog: InterceptionResult[] = [];
79	  /** Index into toolLog marking where the current goal started. Tool calls
80	   *  before this index belong to previous (completed) goals and must not
81	   *  be fed to the judge — otherwise stale actions from earlier turns get
82	   *  interpreted as "trajectory" for the current task. */
83	  private goalStartIndex: number = 0;
84	
85	  constructor(config?: InterceptorConfig) {
86	    this.config = { ...DEFAULTS, ...config };
87	    this.driftDetector = new DriftDetector(this.config.embeddingModel);
88	    this.judge = new IntentJudge(this.config.judgeModel, this.config.judgeBackend);
89	  }
90	
91	  async preflight(): Promise<void> {
92	    const usingBedrockEmbed = isBedrockModel(this.config.embeddingModel);
93	    const usingBedrockJudge = this.config.judgeBackend === "bedrock";
94	
95	    // Check Ollama only for whichever components actually use it
96	    if (!usingBedrockEmbed || !usingBedrockJudge) {
97	      const ollamaModels = [
98	        ...(!usingBedrockEmbed ? [this.config.embeddingModel] : []),
99	        ...(!usingBedrockJudge ? [this.config.judgeModel] : []),
100	      ];
101	      const { ok, missing } = await checkOllama(ollamaModels[0], ollamaModels[1]);
102	      if (!ok) {
103	        console.error(`Missing Ollama models: ${missing.join(", ")}`);
104	        for (const m of missing) console.error(`  ollama pull ${m}`);
105	        throw new Error(`Missing Ollama models: ${missing.join(", ")}`);
106	      }
107	    }
108	
109	    // Check Bedrock for whichever components use it
110	    if (usingBedrockJudge) {
111	      const bedrockOk = await checkBedrock(this.config.judgeModel);
112	      if (!bedrockOk) {
113	        throw new Error(
114	          `Bedrock judge model ${this.config.judgeModel} not accessible. ` +
115	          `Check AWS credentials and that the model is enabled.`
116	        );
117	      }
118	    }
119	
120	    // Live embedding test
121	    const embedStart = Date.now();
122	    try {
123	      const vecs = await embedAny("preflight connectivity test", this.config.embeddingModel);
124	      if (!vecs?.[0]?.length) throw new Error("empty embedding response");
125	      console.log(
126	        `  ✓ Embedding model OK (${this.config.embeddingModel}, ` +
127	        `dim=${vecs[0].length}, ${Date.now() - embedStart}ms)`
128	      );
129	    } catch (err) {
130	      throw new Error(
131	        `Embedding model ${this.config.embeddingModel} failed: ${err instanceof Error ? err.message : String(err)}`
132	      );
133	    }
134	
135	    const judgeStart = Date.now();
136	    try {
137	      if (this.config.judgeBackend === "bedrock") {
138	        const r = await bedrockChat("You are a test.", "Reply with the single word: ok", this.config.judgeModel);
139	        if (!r.content) throw new Error("empty response");
140	      } else {
141	        const r = await chat(
142	          [{ role: "user", content: "Reply with the single word: ok" }],
143	          this.config.judgeModel
144	        );
145	        if (!r.content) throw new Error("empty response");
146	      }
147	      console.log(
148	        `  ✓ Judge model OK (${this.config.judgeBackend}/${this.config.judgeModel}, ` +
149	        `${Date.now() - judgeStart}ms)`
150	      );
151	    } catch (err) {
152	      throw new Error(
153	        `Judge model ${this.config.judgeModel} failed: ${err instanceof Error ? err.message : String(err)}`
154	      );
155	    }
156	  }
157	
158	  async registerGoal(task: string): Promise<void> {
159	    this.originalTask = task;
160	    // Anything in toolLog before this point belongs to a previous goal —
161	    // remember the boundary so recent-history for the judge is scoped to
162	    // just the current task.
163	    this.goalStartIndex = this.toolLog.length;
164	    await this.driftDetector.registerGoal(task);
165	  }
166	
167	  getCurrentGoal(): string {
168	    return this.originalTask;
169	  }
170	
171	  /**
172	   * Evaluate a tool call. Returns whether it should be allowed.
173	   * This is the PreToolUse hook implementation.
174	   *
175	   * @param fileContext — optional assembled file content from SessionTracker.
176	   *   When a Bash command references files written this session, pass
177	   *   getFileContextForJudge() so the judge can see the assembled payload.
178	   */
179	  async evaluate(
180	    tool: string,
181	    input: Record<string, unknown>,
182	    fileContext?: string,
183	    sessionId?: string,
184	    projectRoot?: string | null
185	  ): Promise<InterceptionResult> {
186	    const start = Date.now();
187	
188	    // --- Stage 1: Policy engine ---
189	    const policyResult = evaluateToolPolicy(tool, input, projectRoot);
190	
191	    if (policyResult.decision === "allow") {
192	      const result: InterceptionResult = {
193	        allowed: true,
194	        tool,
195	        input,
196	        stage: "policy-allow",
197	        policyResult,
198	        similarity: null,
199	        judgeVerdict: null,
200	        evaluationMs: Date.now() - start,
201	        reason: policyResult.reason,
202	      };
203	      this.log(result, sessionId);
204	      return result;
205	    }
206	
207	    if (policyResult.decision === "deny") {
208	      const result: InterceptionResult = {
209	        allowed: false,
210	        tool,
211	        input,
212	        stage: "policy-deny",
213	        policyResult,
214	        similarity: null,
215	        judgeVerdict: null,
216	        evaluationMs: Date.now() - start,
217	        reason: policyResult.reason,
218	      };
219	      this.log(result, sessionId);
220	      return result;
221	    }
222	
223	    // --- Stage 2: Embedding drift check ---
224	    const toolDescription = this.describeToolCall(tool, input);
225	    const drift = await this.driftDetector.evaluate(toolDescription);
226	
227	    if (drift.similarity >= this.config.reviewThreshold) {
228	      // High similarity to original task — allow
229	      const result: InterceptionResult = {
230	        allowed: true,
231	        tool,
232	        input,
233	        stage: "drift-allow",
234	        policyResult,
235	        similarity: drift.similarity,
236	        judgeVerdict: null,
237	        evaluationMs: Date.now() - start,
238	        reason: `Similarity ${drift.similarity.toFixed(3)} >= threshold ${this.config.reviewThreshold}`,
239	      };
240	      this.log(result, sessionId);
241	      return result;
242	    }
243	
244	    if (drift.similarity < this.config.denyThreshold) {
245	      // Very low similarity — auto-deny without judge
246	      const result: InterceptionResult = {
247	        allowed: false,
248	        tool,
249	        input,
250	        stage: "drift-deny",
251	        policyResult,
252	        similarity: drift.similarity,
253	        judgeVerdict: null,
254	        evaluationMs: Date.now() - start,
255	        reason: `Similarity ${drift.similarity.toFixed(3)} < deny threshold ${this.config.denyThreshold}`,
256	      };
257	      this.log(result, sessionId);
258	      return result;
259	    }
260	
261	    // --- Stage 3: LLM judge ---
262	    if (!this.config.enableJudge) {
263	      // No judge enabled — default deny for ambiguous cases
264	      const result: InterceptionResult = {
265	        allowed: false,
266	        tool,
267	        input,
268	        stage: "drift-deny",
269	        policyResult,
270	        similarity: drift.similarity,
271	        judgeVerdict: null,
272	        evaluationMs: Date.now() - start,
273	        reason: `Similarity ${drift.similarity.toFixed(3)} in review zone, judge disabled`,
274	      };
275	      this.log(result, sessionId);
276	      return result;
277	    }
278	
279	    // Only consider tool calls taken since the current goal was registered.
280	    // Earlier calls belong to a previous (completed) user task and would
281	    // mislead the judge into thinking the agent has drifted.
282	    const currentGoalTools = this.toolLog.slice(this.goalStartIndex);
283	    const recentTools = currentGoalTools.slice(-5).map(
284	      (r) => `${r.tool}(${this.describeToolCall(r.tool, r.input).substring(0, 80)})`
285	    );
286	
287	    // Build the current action description, enriched with file context
288	    let currentAction = `${tool}(${toolDescription})`;
289	    if (fileContext) {
290	      currentAction += `\n\nFILE CONTEXT (files written during this session):\n${fileContext}`;
291	    }
292	
293	    const judgeVerdict = await this.judge.evaluate(
294	      this.originalTask,
295	      recentTools,
296	      currentAction
297	    );
298	
299	    // Only "hijacked" is denied. "consistent" and "drifting" are allowed.
300	    // "drifting" means the agent may be going off-task but it's not malicious —
301	    // the systemMessage reminder (injected at UserPromptSubmit) handles this.
302	    const allowed = judgeVerdict.verdict !== "hijacked";
303	    const result: InterceptionResult = {
304	      allowed,
305	      tool,
306	      input,
307	      stage: allowed ? "judge-allow" : "judge-deny",
308	      policyResult,
309	      similarity: drift.similarity,
310	      judgeVerdict,
311	      evaluationMs: Date.now() - start,
312	      reason: `Judge: ${judgeVerdict.verdict} (${judgeVerdict.reasoning})`,
313	    };
314	    this.log(result);
315	    return result;
316	  }
317	
318	  /**
319	   * Create a text description of a tool call for embedding.
320	   */
321	  private describeToolCall(
322	    tool: string,
323	    input: Record<string, unknown>
324	  ): string {
325	    switch (tool) {
326	      case "Read":
327	        return `Read file: ${input.file_path}`;
328	      case "Write":
329	        return `Write file: ${input.file_path} with content about ${String(input.content ?? "").substring(0, 100)}`;
330	      case "Edit":
331	        return `Edit file: ${input.file_path}`;
332	      case "Bash":
333	        return `Execute command: ${String(input.command ?? "").substring(0, 200)}`;
334	      case "Glob":
335	        return `Find files matching: ${input.pattern}`;
336	      case "Grep":
337	        return `Search for: ${input.pattern}`;
338	      default:
339	        return `${tool}: ${JSON.stringify(input).substring(0, 200)}`;
340	    }
341	  }
342	
343	  private log(result: InterceptionResult, sessionId?: string): void {
344	    this.toolLog.push(result);
345	
346	    const icon =
347	      result.stage.endsWith("-allow") ? "✓" :
348	      result.stage.endsWith("-deny") ? "✗" : "?";
349	    const simStr = result.similarity !== null
350	      ? ` sim=${result.similarity.toFixed(3)}`
351	      : "";
352	    const judgeStr = result.judgeVerdict
353	      ? ` judge=${result.judgeVerdict.verdict}(${result.judgeVerdict.durationMs}ms)`
354	      : "";
355	    const sessionStr = sessionId ? ` [${sessionId.substring(0, 8)}]` : "";
356	
357	    console.log(
358	      `   ${sessionStr} [${icon} ${result.stage}]${simStr}${judgeStr} ${result.tool}: ${result.reason} (${result.evaluationMs}ms)`
359	    );
360	  }
361	
362	  getLog(): InterceptionResult[] {
363	    return this.toolLog;
364	  }
365	
366	  reset(): void {
367	    this.toolLog = [];
368	    this.originalTask = "";
369	    this.goalStartIndex = 0;
370	    this.driftDetector.reset();
371	  }
372	}
